  ('medical-tech-moex-02128', 'medical-tech', 'medical-tech-moex-114-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有  關病毒性肝炎之臨床症狀，下列何者最適當？', '["A 型肝炎病毒感染之病程較B型肝炎病毒長", "A 型肝炎病毒之急性感染，兒童較成人症狀嚴重", "C 型肝炎病毒感染較A型肝炎病毒感染容易變成慢性感染", "D 型肝炎病毒感染與造成嚴重猛爆性肝炎症狀無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "41bdf8dff33c", "answer_pdf_sha1": "864b0ac22417", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
